function gcd(a, b) {
   if (b === 0) return a;
   return gcd(b, a % b);
}

function hasGroupsSizeX(deck) {
    const counts = {};
    for (const card of deck) {
        if (card in counts) {
            counts[card]++;
        } else {
            counts[card] = 1;
        }
    }
    let gcd_result = 0;
    for (const count in counts) {
        gcd_result = gcd(gcd_result, counts[count]);
    }
    return gcd_result > 1;
}
